<script lang="ts">let{data,form}=$props();let q=$state('');let filtered=$derived(data.sites.filter((s:any)=>`${s.name} ${s.url} ${s.categoryName}`.toLowerCase().includes(q.toLowerCase())));</script><svelte:head><title>导航收藏｜暮色工作台</title></svelte:head>
<header class="studio-head"><div><p class="eyebrow">WAYPOINTS</p><h1>导航收藏</h1><p>收藏按分类分组展示，新增时会自动尝试识别网站图标。</p></div></header>{#if form?.message}<div class:success={form.success} class="notice">{form.message}</div>{/if}
<div class="manager-grid"><section class="studio-panel"><div class="panel-bar"><input class="filter" bind:value={q} placeholder="搜索名称、网址或分类" /><a class="primary small" href="#editor">＋ 新网站</a></div><div class="grouped-sites">{#each data.categories as category}{@const items=filtered.filter((site:any)=>site.categoryId===category.id)}{#if items.length}<section><header><div><i style={`background:${category.color}`}></i><h2>{category.name}</h2></div><span>{items.length} 个网站</span></header><div class="manage-list">{#each items as site}<article><div class="site-icon mini">{#if site.icon}<img src={site.icon} alt="" />{:else}{site.name.slice(0,1)}{/if}</div><div><b>{site.name}</b><small>{site.status==='draft'?'草稿':'公开'} · 排序 {site.sortOrder}</small><span>{site.url}</span></div><div class="row-actions"><form method="POST" action="?/icon"><input type="hidden" name="id" value={site.id}/><button title="重新识别网站图标">识别图标</button></form><a href={`?edit=${site.id}#editor`}>编辑</a><form method="POST" action="?/delete" onsubmit={(e)=>!confirm('确定删除这个网站？')&&e.preventDefault()}><input type="hidden" name="id" value={site.id}/><button class="danger">删除</button></form></div></article>{/each}</div></section>{/if}{/each}{#if !filtered.length}<div class="empty">没有匹配的网站。</div>{/if}</div></section>
  <section class="studio-panel editor" id="editor"><p class="eyebrow">{data.editing?'EDIT':'NEW'}</p><h2>{data.editing?'编辑网站':'添加一个坐标'}</h2><form method="POST" action="?/save" enctype="multipart/form-data" class="studio-form"><input type="hidden" name="id" value={data.editing?.id||''}/><input type="hidden" name="icon" value={data.editing?.icon||''}/><label>网站名称<input name="name" value={data.editing?.name||''} required /></label><label>网址<input name="url" type="url" value={data.editing?.url||''} placeholder="https://" required /></label><label>网址标识 <small>用于内部识别，留空将根据网站名称自动生成</small><input name="slug" value={data.editing?.slug||''} placeholder="例如：github" /></label><label>一句话描述<textarea name="description" rows="3">{data.editing?.description||''}</textarea></label><div class="two"><label>分类<select name="categoryId" required>{#each data.categories as c}<option value={c.id} selected={c.id===data.editing?.categoryId}>{c.name}</option>{/each}</select></label><label>排序<input name="sortOrder" type="number" value={data.editing?.sortOrder||100}/></label></div><div class="two"><label>状态<select name="status"><option value="published" selected={data.editing?.status!=='draft'}>公开</option><option value="draft" selected={data.editing?.status==='draft'}>草稿</option></select></label><label>手动上传图标<input name="iconFile" type="file" accept="image/png,image/jpeg,image/webp,image/gif" /></label></div><label class="check"><input name="autoIcon" type="checkbox" checked={!data.editing}/> 保存时自动识别网站图标</label><label class="check"><input name="featured" type="checkbox" checked={Boolean(data.editing?.featured)}/> 首页精选</label><button class="primary">保存网站</button><small>手动上传的图片优先；自动识别失败不会影响网站保存。</small></form></section></div>
